targets.walnut_predicate:
# Thue–Morse is built in to Walnut as the 2-automatic word T (T[n]=s2(n) mod 2).
# (1) Overlap-freeness — TRUE (no overlap exists, for all i,p, unbounded):
eval tm_overlapfree "?msd_2 Ai Ap (p>=1) => ~(Aj (j<p+1) => T[i+j]=T[i+j+p])";
# helper: an overlap of period p at i is a length-(2p+1) factor with T[i+j]=T[i+j+p] for all j<=p.

# (2) A square of period p exists somewhere — used to show squares of every period >= some bound:
def tm_sq_per "?msd_2 Ei (p>=1) & (Aj (j<p) => T[i+j]=T[i+p+j])";
# (2') Arbitrarily large squares — TRUE (for every bound there is a longer square period):
eval tm_arbitrary_squares "?msd_2 Ap Eq (q>=p) & $tm_sq_per(q)";

# Critical exponent exactly 2 is then witnessed by (1)=TRUE (no factor of exponent>2 -> sup<=2 via
# the overlap automaton) together with (2')=TRUE (squares, exponent 2, of unbounded period -> sup>=2,
# attained as a limit). Walnut also computes the critical exponent directly via its rep/factor machinery;
# all predicates are FO over <N,+,<,T[.]> with addition-only offsets (i+j, i+j+p), no variable*variable.

# Fibonacci word f loaded under Fibonacci/Zeckendorf numeration (msd_fib);
# its automaton + the Pisot adder are exactly the spec's in-scope class.
# Factor equality (synchronized FO, addition only — no var*var):
def feq "?msd_fib (i+n)<=N & (j+n)<=N & At (t<n) => F[i+t]=F[j+t]":
# "window [p, p+m) contains some occurrence of the length-n factor starting at i":
def occ "?msd_fib Ex (p<=x) & (x+n<=p+m) & $feq(x,i,n)":
# "every length-n factor of f occurs inside window [p, p+m)":
def covers "?msd_fib Ai (i+n<=N) => $occ(p,m,i,n)":
# "m is a valid recurrence length for n" (holds for all windows):
def valid "?msd_fib Ap (p+m<=N) => $covers(p,m,n)":
# R(n)=m is the LEAST valid m -> synchronized predicate; Walnut synthesizes the
# Fibonacci automaton for the (n,m) graph of R:
def Rsync "?msd_fib $valid(m,n) & (Am2 (m2<m) => ~$valid(m2,n))":
# Refuting the stated identity (the actual sound output): assert it never matches
# the claimed RHS once Fibonacci constants are encoded as synchronized terms.
eval bad "?msd_fib En $Rsync(n,m) & m != claimed_R(n)":   # returns TRUE (counterexamples exist)
